Build the conversation step by step, verifying message structure at each stage.

```rust
#[tokio::test]
async fn test_full_agentic_loop() {
    let mut engine = ConversationEngine::new(
        "You are a helpful assistant.".to_string(), vec![], 32000,
    );
    let registry = ToolRegistry::with_defaults();
    let ctx = ToolContext { cwd: PathBuf::from("/tmp"), project_path: PathBuf::from("/tmp") };

    // Step 1: User asks to list files
    engine.add_user_message("List files in /tmp");
    assert_eq!(engine.message_count(), 1);
    assert_eq!(engine.messages()[0].role, Role::User);

    // Step 2: Simulate model responding with a tool call
    let tool_call = ToolCall {
        id: "tc_1".to_string(),
        name: "bash".to_string(),
        arguments: json!({ "command": "ls /tmp" }),
    };
    engine.add_assistant_message(tool_call_response(vec![tool_call.clone()]));
    assert_eq!(engine.message_count(), 2);

    // Step 3: Execute the tool
    let result = registry.execute("bash", tool_call.arguments.clone(), &ctx).await.unwrap();
    assert!(!result.is_error);

    // Step 4: Feed result back as tool message
    engine.add_tool_result(&tool_call.id, &result.output);
    assert_eq!(engine.messages()[2].role, Role::Tool);
    assert_eq!(engine.messages()[2].tool_call_id, Some("tc_1".to_string()));

    // Step 5: Model produces final text
    engine.add_assistant_message(text_response("Here are the files."));

    // Verify full message order
    assert_eq!(engine.messages()[0].role, Role::User);
    assert_eq!(engine.messages()[1].role, Role::Assistant);
    assert_eq!(engine.messages()[2].role, Role::Tool);
    assert_eq!(engine.messages()[3].role, Role::Assistant);
}
```

This tests the critical invariant: conversation always alternates user/assistant, with tool results being user messages. Each step verifies both the role and the content shape.

Feed the input one character at a time -- this is the hardest case for any streaming parser because every boundary is tested.

```rust
#[test]
fn test_single_char_chunks() {
    let mut parser = StreamingToolCallParser::new();
    let input = "<tool_call>\n<function=bash>\n<parameter=command>ls</parameter>\n</function>\n</tool_call>";

    let mut all = Vec::new();
    for ch in input.chars() {
        all.extend(parser.feed(&ch.to_string()));
    }
    all.extend(parser.flush());

    let complete: Vec<&ParsedToolCall> = all.iter()
        .filter_map(|e| match e {
            StreamEvent::ToolCallComplete(c) => Some(c),
            _ => None,
        })
        .collect();

    assert_eq!(complete.len(), 1);
    assert_eq!(complete[0].name, "bash");
}
```

Also test the split-across-chunks case:
```rust
#[test]
fn test_tool_call_split_across_chunks() {
    let mut parser = StreamingToolCallParser::new();

    // Split in the middle of the opening tag
    let e1 = parser.feed("Some text <tool_");
    let e2 = parser.feed("call>\n<function=bash>\n<parameter=command>ls</para");
    let e3 = parser.feed("meter>\n</function>\n</tool_call> done");

    let mut all = Vec::new();
    all.extend(e1); all.extend(e2); all.extend(e3);
    all.extend(parser.flush());

    assert!(all.iter().any(|e| matches!(e, StreamEvent::ToolCallStart)));
    let complete: Vec<_> = all.iter()
        .filter_map(|e| match e { StreamEvent::ToolCallComplete(c) => Some(c), _ => None })
        .collect();
    assert_eq!(complete.len(), 1);
    assert_eq!(complete[0].name, "bash");
}
```

The single-char test catches off-by-one errors in buffer management. The split-across-chunks test catches partial-tag matching bugs.

Test with both matching and non-matching project paths to verify scoping works.

```rust
#[test]
fn test_rules_scope_matching() {
    let mut engine = RulesEngine::new();
    let project = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    let rules_text = format!(r#"
scope "{}" {{
  rule "no-force-push" {{
    on tool:git
    reject contains(command, "push --force")
    reason "No force pushes in this project"
  }}
}}
"#, project.display());
    engine.load(&rules_text).unwrap();

    let mut ctx = EvalContext::new(RuleEvent::Tool("git".to_string()));
    ctx.set_str("command", "push --force origin main");

    // Matching project path -> should reject
    let result = engine.evaluate(&ctx, Some(&project.to_string_lossy()));
    assert!(matches!(result, RuleAction::Reject(_)));
}

#[test]
fn test_rules_scope_no_match() {
    let mut engine = RulesEngine::new();
    engine.load(r#"
scope "/some/other/project" {
  rule "no-force-push" {
    on tool:git
    reject contains(command, "push --force")
    reason "No force pushes"
  }
}
"#).unwrap();

    let mut ctx = EvalContext::new(RuleEvent::Tool("git".to_string()));
    ctx.set_str("command", "push --force origin main");

    // Different project path -> scope doesn't apply -> allow
    let result = engine.evaluate(&ctx, Some("/different/project"));
    assert!(matches!(result, RuleAction::Allow));
}
```

The two tests together prove that scope matching is both inclusive (matching path triggers the rule) and exclusive (non-matching path doesn't). Using `CARGO_MANIFEST_DIR` for the matching test ensures the path is always valid on the test machine.

