```swift
func test_confidenceThresholds_mutuallyExclusive() {
    let testValues = stride(from: 0.0, through: 1.0, by: 0.1)
    for value in testValues {
        let discard = ConfidenceThresholds.shouldDiscard(value)
        let review = ConfidenceThresholds.needsReview(value)
        let auto = ConfidenceThresholds.canAutoCreate(value)

        let trueCount = [discard, review, auto].filter { $0 }.count
        XCTAssertEqual(trueCount, 1,
            "Confidence \(value) should fall into exactly one bucket, got \(trueCount)")
    }
}
```

