```swift
func test_confidenceThresholds_shouldDiscard() {
    XCTAssertTrue(ConfidenceThresholds.shouldDiscard(0.49))
    XCTAssertTrue(ConfidenceThresholds.shouldDiscard(0.0))
    XCTAssertFalse(ConfidenceThresholds.shouldDiscard(0.5))
}

func test_confidenceThresholds_needsReview() {
