    XCTAssertTrue(ConfidenceThresholds.needsReview(0.5))   // at minimum
    XCTAssertTrue(ConfidenceThresholds.needsReview(0.69))  // just below review
    XCTAssertFalse(ConfidenceThresholds.needsReview(0.7))  // at review threshold
