/// Both write paths (MemoryToolHandler + PersonalFactExtractor) should produce
/// the same key/value format for identical input
func test_memoryToolRemember_matchesExtractorFormat() async {
    let testFact = "my favorite color is blue"

    // Path 1: Tool handler (LLM tool call path)
    let _ = await handler.execute(
        action: "remember",
        params: ["fact": testFact, "category": "preference"]
    )
    let factsAfterTool = await UserFTAIManager.shared.getAllFacts()
    let toolFact = factsAfterTool.first {
        $0.key.lowercased().contains("color") ||
        $0.key.lowercased().contains("favorite")
    }

    // Path 2: PersonalFactExtractor (passive extraction path)
    let extracted = await PersonalFactExtractor.shared.extractAndSave(from: testFact)
    let factsAfterExtractor = await UserFTAIManager.shared.getAllFacts()
    let extractorFact = factsAfterExtractor.first {
        $0.key.lowercased().contains("color") ||
        $0.key.lowercased().contains("favorite")
    }

    XCTAssertNotNil(toolFact, "Tool handler should have stored a fact")
    XCTAssertNotNil(extractorFact, "Extractor should have stored a fact")

    if let tf = toolFact, let ef = extractorFact {
        XCTAssertEqual(tf.key.lowercased(), ef.key.lowercased(),
