**Requirement:** Classify tool calls into Safe, Write, or Destructive tiers. Git push is always Destructive. Git status/diff/log are Safe.

**Step 1: Write the tests first (red):**
```rust
#[test]
fn test_classify_git_safe() {
    assert_eq!(classify("git", &json!({"subcommand": "status"})), PermissionTier::Safe);
    assert_eq!(classify("git", &json!({"subcommand": "diff"})), PermissionTier::Safe);
    assert_eq!(classify("git", &json!({"subcommand": "log"})), PermissionTier::Safe);
}

#[test]
fn test_classify_git_destructive() {
    assert_eq!(classify("git", &json!({"subcommand": "push"})), PermissionTier::Destructive);
    assert_eq!(
        classify("git", &json!({"subcommand": "reset", "args": "--hard HEAD~1"})),
        PermissionTier::Destructive
    );
}

#[test]
fn test_classify_git_write() {
    assert_eq!(classify("git", &json!({"subcommand": "add"})), PermissionTier::Write);
    assert_eq!(classify("git", &json!({"subcommand": "commit"})), PermissionTier::Write);
}
```

**Step 2: Implement to make tests green:**
```rust
fn classify_git(params: &Value) -> PermissionTier {
    let subcommand = params.get("subcommand").and_then(|v| v.as_str()).unwrap_or("");
    let args = params.get("args").and_then(|v| v.as_str()).unwrap_or("");

    match subcommand {
        "status" | "diff" | "log" | "show" => PermissionTier::Safe,
        "push" => PermissionTier::Destructive,
        "reset" if args.contains("--hard") => PermissionTier::Destructive,
        "add" | "commit" | "checkout" | "merge" => PermissionTier::Write,
        _ => PermissionTier::Write,
    }
}
```

**Step 3: Add edge cases:**
```rust
#[test]
fn test_classify_git_branch_depends_on_args() {
    // branch (list) is safe
    assert_eq!(classify("git", &json!({"subcommand": "branch"})), PermissionTier::Safe);
    // branch -d is write
    assert_eq!(
        classify("git", &json!({"subcommand": "branch", "args": "-d feature"})),
        PermissionTier::Write
    );
}
