Test commands joined by `&&`, `||`, `;`, and `|` where segments have different tiers.

```rust
#[test]
fn test_classify_bash_compound_worst_wins() {
    // Safe && Destructive = Destructive
    assert_eq!(
        classify("bash", &json!({"command": "ls -la && rm file.txt"})),
        PermissionTier::Destructive
    );

    // Safe | Safe = Safe
    assert_eq!(
        classify("bash", &json!({"command": "ls | grep foo"})),
        PermissionTier::Safe
    );

    // Safe ; Write ; Destructive = Destructive
    assert_eq!(
        classify("bash", &json!({"command": "ls ; echo hi ; rm file"})),
        PermissionTier::Destructive
    );
}
```

